hooks.command:
echo "$CLAUDE_TOOL_INPUT" | python3 -c "
import sys, json
try:
    inp = json.load(sys.stdin)
    cmd = inp.get('command', '')
    dangerous = ['rm -rf', 'git push --force', 'git reset --hard', 'git checkout .', 'drop table', 'DELETE FROM']
    for d in dangerous:
        if d in cmd:
            print(f'BLOCKED: 危険なコマンドが検出されました: {d}', file=sys.stderr)
            exit(1)
except:
    pass
"
